__modules["json"] = function()
-- 轻量 JSON 编解码（Lua 5.1 + LuaSocket 环境无 cjson 时使用）

local json = {}

local escape_map = {
  ["\\"] = "\\\\",
  ["\""] = "\\\"",
  ["\b"] = "\\b",
  ["\f"] = "\\f",
  ["\n"] = "\\n",
  ["\r"] = "\\r",
  ["\t"] = "\\t",
}

local function escape_str(s)
  return (s:gsub('[\\"\b\f\n\r\t]', escape_map))
end

local function encode_value(v, stack)
  local t = type(v)
  if t == "nil" then
    return "null"
  elseif t == "boolean" then
    return v and "true" or "false"
  elseif t == "number" then
    return tostring(v)
  elseif t == "string" then
    return '"' .. escape_str(v) .. '"'
  elseif t == "table" then
    if stack[v] then
      error("json.encode: circular reference")
    end
    stack[v] = true

    local is_array = #v > 0
    local parts = {}
    if is_array then
      for i = 1, #v do
        parts[#parts + 1] = encode_value(v[i], stack)
      end
      stack[v] = nil
      return "[" .. table.concat(parts, ",") .. "]"
    end

    for k, val in pairs(v) do
      if type(k) == "string" then
        parts[#parts + 1] = '"' .. escape_str(k) .. '":' .. encode_value(val, stack)
      end
    end
    stack[v] = nil
    return "{" .. table.concat(parts, ",") .. "}"
  end
  error("json.encode: unsupported type " .. t)
end

function json.encode(v)
  return encode_value(v, {})
end

-- 简易解码，覆盖 API 常见响应结构即可
local function skip_ws(s, i)
  while true do
    local c = s:sub(i, i)
    if c == "" or not c:match("%s") then
      return i
    end
    i = i + 1
  end
end

local function parse_value(s, i)
  i = skip_ws(s, i)
  local c = s:sub(i, i)
  if c == "{" then
    local obj = {}
    i = i + 1
    while true do
      i = skip_ws(s, i)
      if s:sub(i, i) == "}" then
        return obj, i + 1
      end
      if s:sub(i, i) ~= '"' then
        error("json.decode: expected string key at " .. i)
      end
      local k
      k, i = parse_value(s, i)
      i = skip_ws(s, i)
      if s:sub(i, i) ~= ":" then
        error("json.decode: expected ':' at " .. i)
      end
      local val
      val, i = parse_value(s, i + 1)
      obj[k] = val
      i = skip_ws(s, i)
      local sep = s:sub(i, i)
      if sep == "}" then
        return obj, i + 1
      elseif sep ~= "," then
        error("json.decode: expected ',' at " .. i)
      end
      i = i + 1
    end
  elseif c == "[" then
    local arr = {}
    i = i + 1
    if s:sub(i, i) == "]" then
      return arr, i + 1
    end
    while true do
      local val
      val, i = parse_value(s, i)
      arr[#arr + 1] = val
      i = skip_ws(s, i)
      local sep = s:sub(i, i)
      if sep == "]" then
        return arr, i + 1
      elseif sep ~= "," then
        error("json.decode: expected ',' at " .. i)
      end
      i = i + 1
    end
  elseif c == '"' then
    local j = i + 1
    local buf = {}
    while j <= #s do
      local ch = s:sub(j, j)
      if ch == '"' then
        return table.concat(buf), j + 1
      elseif ch == "\\" then
        local esc = s:sub(j + 1, j + 1)
        local map = { n = "\n", r = "\r", t = "\t", b = "\b", f = "\f", ['"'] = '"', ["\\"] = "\\" }
        buf[#buf + 1] = map[esc] or esc
        j = j + 2
      else
        buf[#buf + 1] = ch
        j = j + 1
      end
    end
    error("json.decode: unterminated string")
  elseif c == "t" and s:sub(i, i + 3) == "true" then
    return true, i + 4
  elseif c == "f" and s:sub(i, i + 4) == "false" then
    return false, i + 5
  elseif c == "n" and s:sub(i, i + 3) == "null" then
    return nil, i + 4
  else
    local num = s:match("^%-?%d+%.?%d*[eE%-%+]?%d*", i)
    if num and #num > 0 then
      return tonumber(num), i + #num
    end
    error("json.decode: unexpected token at " .. i)
  end
end

function json.decode(s)
  if not s or s == "" then
    return nil
  end
  local value, rest = parse_value(s, 1)
  rest = skip_ws(s, rest or 1)
  if rest <= #s then
    error("json.decode: trailing characters at " .. rest)
  end
  return value
end

return json

end

__modules["session"] = function()
-- Session 生命周期（模块 01）

local Session = {}

function Session.create(client, name)
  local res, err = client:post("/session/create", {
    name = name or "memo-reminder",
    debugRequestLog = true,
    localControl = { enabled = true },
  })
  if not res then
    return nil, err
  end
  local sessionId = res.value and res.value.sessionId
  if not sessionId then
    return nil, "创建 Session 失败：未返回 sessionId"
  end
  client:setSession(sessionId)
  return sessionId, nil
end

function Session.close(client, sessionId)
  client:setSession(sessionId)
  client:delete("/session", { sessionId = sessionId })
  client:setSession(nil)
end

return Session

end

__modules["run_memo_task"] = function()
-- 核心自动化流程：打开备忘录 → 新建 → 写入 → 保存进度

local App = require("app")
local Element = require("element")
local Prefs = require("prefs")
local Ui = require("ui")
local Utils = require("utils")

local Task = {}

local function pickTemplate(templates, lastIndex)
  if #templates == 0 then
    return nil, "没有可用模板"
  end
  local nextIndex = ((lastIndex or 0) % #templates) + 1
  return templates[nextIndex], nextIndex
end

function Task.run(client, config, templates)
  Utils.ensureLogDir(client, config.logPath)
  Utils.log(client, config.logPath, "任务开始")

  local lastIndex = Prefs.get(client, config.prefsNamespace, "lastTemplateIndex", 0) or 0
  local template, templateIndex = pickTemplate(templates, lastIndex)
  if not template then
    return false, templateIndex
  end

  Ui.toast(client, "准备打开备忘录…")
  Utils.log(client, config.logPath, "启动 App: " .. config.bundleId)

  local ok, err = App.launch(client, config.bundleId, config.timeouts.appLaunch)
  if not ok then
    Ui.toast(client, "启动失败: " .. tostring(err))
    return false, err
  end
  Utils.sleep(config.timeouts.betweenSteps)

  -- 解锁屏幕后若仍在列表页，点「新建」
  Ui.toast(client, "查找新建按钮…")
  local clicked, clickErr = Element.clickFirstMatching(client, config, {
    config.selectors.composeButton,
    config.selectors.composeButtonEn,
    { labelContains = "撰写" },
    { labelContains = "Compose" },
  })
  if not clicked then
    Utils.log(client, config.logPath, "新建按钮未找到: " .. tostring(clickErr))
    Ui.toast(client, "未找到新建按钮，请检查 selectors")
    return false, clickErr
  end
  Utils.sleep(config.timeouts.betweenSteps)

  -- 输入标题
  Ui.toast(client, "写入标题…")
  local titleOk = Element.input(client, config, config.selectors.titleField, template.title, {
    clearBeforeInput = true,
  })
  if not titleOk then
    -- 部分版本标题与正文在同一 TextField，退化为直接输入全文
    Utils.log(client, config.logPath, "标题输入框未命中，尝试写入正文区")
  else
    Utils.sleep(300)
    Element.input(client, config, config.selectors.bodyField, template.body, {
      append = false,
    })
  end

  if not titleOk then
    local fullText = template.title .. "\n\n" .. template.body
    Element.input(client, config, { type = "TextField" }, fullText, {
      clearBeforeInput = true,
    })
  end

  Utils.sleep(config.timeouts.betweenSteps)

  -- 保存运行进度
  local runCount = Prefs.incrementRunCount(client, config.prefsNamespace)
  Prefs.set(client, config.prefsNamespace, "lastTemplateIndex", templateIndex)
  Prefs.set(client, config.prefsNamespace, "lastMemoId", template.id)

  Utils.log(client, config.logPath, string.format(
    "完成 template=%s index=%d runCount=%d",
    template.id,
    templateIndex,
    runCount
  ))

  Ui.toast(client, string.format("已创建「%s」(#%d)", template.title, runCount), 2500)
  return true, nil
end

return Task

end

__modules["app"] = function()
-- 应用管理封装（模块 03）

local App = {}

function App.ensureFront(client, bundleId, timeoutMs)
  local deadline = os.time() + math.ceil(timeoutMs / 1000)
  while os.time() <= deadline do
    local res = client:get("/app/frontBid")
    if res and res.value == bundleId then
      return true
    end
    require("socket").sleep(0.3)
  end
  return false
end

function App.launch(client, bundleId, timeoutMs)
  local res, err = client:post("/app/run", { bundleId = bundleId })
  if not res or not res.value then
    return false, err or "启动 App 失败"
  end
  if not App.ensureFront(client, bundleId, timeoutMs) then
    return false, "App 未进入前台: " .. bundleId
  end
  return true, nil
end

return App

end

__modules["element"] = function()
-- 元素查找与操作封装（模块 08）

local Element = {}

local function mergeOptions(config, extra)
  local options = { maxDepth = config.elementMaxDepth }
  if extra then
    for k, v in pairs(extra) do
      options[k] = v
    end
  end
  return options
end

function Element.waitFor(client, config, query, timeoutMs, expectPresent)
  local res, err = client:post("/element/waitFor", {
    query = query,
    options = mergeOptions(config),
    timeoutMs = timeoutMs or config.timeouts.elementWait,
    expectPresent = expectPresent ~= false,
  })
  if not res or not res.value or not res.value.found then
    return nil, err or "元素未出现"
  end
  return res.value.element, nil
end

function Element.click(client, config, query)
  local res, err = client:post("/element/click", {
    query = query,
    options = mergeOptions(config),
  })
  if not res or not res.value then
    return false, err or "点击失败"
  end
  return true, nil
end

function Element.input(client, config, query, text, opts)
  opts = opts or {}
  local res, err = client:post("/element/input", {
    query = query,
    text = text,
    options = mergeOptions(config, opts.options),
    clearBeforeInput = opts.clearBeforeInput ~= false,
    append = opts.append or false,
    submit = opts.submit or false,
  })
  if not res or not res.value then
    return false, err or "输入失败"
  end
  return true, nil
end

function Element.clickFirstMatching(client, config, queries)
  for _, query in ipairs(queries) do
    local ok = Element.click(client, config, query)
    if ok then
      return true, query
    end
  end
  return false, "未找到可点击元素"
end

return Element

end

__modules["prefs"] = function()
-- 用户配置数据封装（模块 19）

local Prefs = {}

function Prefs.get(client, namespace, key, defaultValue)
  local res = client:post("/prefs/get", {
    namespace = namespace,
    key = key,
    defaultValue = defaultValue,
  })
  return res and res.value
end

function Prefs.set(client, namespace, key, value)
  client:post("/prefs/set", {
    namespace = namespace,
    key = key,
    value = value,
  })
end

function Prefs.incrementRunCount(client, namespace)
  local count = Prefs.get(client, namespace, "runCount", 0) or 0
  Prefs.set(client, namespace, "runCount", count + 1)
  Prefs.set(client, namespace, "lastRunAt", os.date("%Y-%m-%d %H:%M:%S"))
  return count + 1
end

return Prefs

end

__modules["ui"] = function()
-- 悬浮 UI 封装（模块 16）

local Ui = {}

function Ui.toast(client, message, durationMs)
  client:post("/ui/toast", {
    message = message,
    durationMs = durationMs or 2000,
  })
end

return Ui

end

__modules["utils"] = function()
-- 通用工具

local socket = require("socket")

local Utils = {}

function Utils.sleep(ms)
  socket.sleep(ms / 1000)
end

function Utils.now()
  return os.date("%Y-%m-%d %H:%M:%S")
end

function Utils.log(client, path, line)
  local text = string.format("[%s] %s\n", Utils.now(), line)
  print(text:sub(1, -2))
  client:post("/file/append", {
    path = path,
    data = text,
    encoding = "utf8",
  })
end

function Utils.ensureLogDir(client, logPath)
  local dir = logPath:match("^(.*)/[^/]+$")
  if not dir then
    return
  end
  local exists = client:get("/file/exists", { path = dir })
  if exists and exists.value == false then
    client:post("/file/directory/create", { path = dir })
  end
end

return Utils

end

__modules["templates"] = function()
-- 备忘录内容模板

return {
  {
    id = "daily_checklist",
    title = "今日待办",
    body = table.concat({
      "□ 回复重要消息",
      "□ 整理截图与文件",
      "□ 备份脚本配置",
      "",
      "—— 由 memo-reminder 自动生成",
    }, "\n"),
  },
  {
    id = "automation_note",
    title = "自动化记录",
    body = table.concat({
      "脚本: memo-reminder",
      "引擎: YKEngine HTTP API",
      "说明: 演示按文件组织的 Lua 自动化示例",
    }, "\n"),
  },
}

end

local __orig_require = require
local function __bundle_require(name)
  local loader = __modules[name]
  if loader then
    local mod = package.loaded[name]
    if mod ~= nil then
      return mod
    end
    mod = loader() or true
    package.loaded[name] = mod
    return mod
  end
  return __orig_require(name)
end
require = __bundle_require

local function __bundle_root()
  local src = debug.getinfo(1, "S").source
  if src:sub(1, 1) == "@" then
    src = src:sub(2)
  end
  return src:match("^(.*)/[^/]+$") or "."
end

local __root = __bundle_root()
package.path = table.concat({
  __root .. "/?.lua",
  __root .. "/?/init.lua",
  package.path,
}, ";")
package.cpath = table.concat({
  __root .. "/lib/lua/5.5/?.so",
  __root .. "/lib/lua/5.5/socket/?.so",
  __root .. "/lib/lua/5.5/mime/?.so",
  package.cpath,
}, ";")

-- 备忘录自动化示例 — 入口
-- 部署: 将整个 memo-reminder 目录复制到 /var/mobile/Library/YKApp/Script/
-- 启动: POST /executor/v1/scripts/run { "scriptName": "memo-reminder/main.lua" }
-- 文档: https://jonathanbasta7029.github.io/docs/

-- bootstrap inlined

local config = require("config")
local YkHttp = require("yk_http")
local Session = require("session")
local Task = require("run_memo_task")
local templates = require("templates")
local Utils = require("utils")

local function main()
  local client = YkHttp.new(config.baseUrl)

  print("[memo-reminder] 检查服务…")
  local health, err = client:get("/health")
  if not health or not health.value or not health.value.ready then
    print("[memo-reminder] 服务不可用: " .. tostring(err))
    os.exit(1)
  end

  local sessionId, sessionErr = Session.create(client, "memo-reminder")
  if not sessionId then
    print("[memo-reminder] Session 创建失败: " .. tostring(sessionErr))
    os.exit(1)
  end
  print("[memo-reminder] Session: " .. sessionId)

  local ok, taskErr = Task.run(client, config, templates)

  Session.close(client, sessionId)

  if not ok then
    print("[memo-reminder] 任务失败: " .. tostring(taskErr))
    os.exit(1)
  end

  print("[memo-reminder] 任务成功 @" .. Utils.now())
  os.exit(0)
end

main()

